css:
:root{
  --header-height:130px;
  --footer-height:130px;
}

*{box-sizing:border-box;}
html,body{margin:0;padding:0;}

@page{
  size:A4;
  margin:5px;
}

/* PAGE CONTAINER */
.outer-box{
  position: relative;
  min-height: calc(297mm - 10px);
  width: 100%;        /* remove fixed mm width */
  margin: auto;
  border: 0.2mm solid #000;
  font-family: Arial, sans-serif;
  font-size: 10pt;
  page-break-after: always;
  overflow: hidden;
}

.outer-box:last-child{
  page-break-after:auto;
}

/* HEADER */
.letter-head{
  position:absolute;
  top:0;
  left:0;
  right:0;
  height:var(--header-height);
}

.letter-head img{
  width:100%;
  height:100%;
  object-fit:fill;
}

/* FOOTER */
.print-footer{
  position:absolute;
  bottom:0;
  left:0;
  right:0;
  height:var(--footer-height);
}

.print-footer img{
  width:100%;
  height:100%;
  object-fit:fill;
}

/* CONTENT AREA */
.content{
  padding-top:var(--header-height);
  padding-bottom:var(--footer-height);
}

/* TITLES */
.stock-transfer-title{
  text-align:center;
  padding:8px;
  font-size:16pt;
  font-weight:bold;
  background:#f0f0f0;
  border:1px solid #000;
}

.items-title{
  text-align:center;
  padding:6px;
  font-weight:bold;
  background:#f0f0f0;
  border:1px solid #000;
}

/* BRANCH SECTION */
.branch-info-section{
  width:100%;
  border-collapse:collapse;
  height:116px;
  border-left:1px solid #000;
  border-right:1px solid #000;
  border-bottom:1px solid #000;
}
.branch-box{
  padding:6px;
  border-right:1px solid #000;
  width:33.33%;
  vertical-align:top;
}
.branch-box:last-child{
  border-right:none;
}
.branch-box:first-child{
    border-left:none;
}

.branch-label{
  font-weight:bold;
  font-size:11pt;
  margin-bottom:4px;
}

.info-row{
  display:flex;
  margin-bottom:6px;
}

.info-label{
  font-weight: bold;
  min-width: 100px;   /* reduced from 130px */
}

/* TABLE */
.items-table{
  width:100%;
  border-collapse:collapse;
}

.items-table th,
.items-table td{
  border:1px solid #000;
  padding:6px;
  font-size:9pt;
}

.items-table th{
  background:#f0f0f0;
  text-align:center;
}

.text-center{
  text-align:center;
}

/* SIGNATURE */
.signature-fixed{
  position:absolute;
  right:12px;
  bottom:calc(var(--footer-height) + 5px);
  font-size:8pt;
  font-weight:bold;
}

/* PRINT CONTROL */
@media print{
  table{page-break-inside:auto;}
  tr{page-break-inside:avoid;}
  thead{display:table-header-group;}
}

html:
{% set items_per_page = 15 %}
{% set total_items = doc.items|length %}
{% set total_pages = (total_items // items_per_page) + (1 if total_items % items_per_page else 0) %}
{% if total_pages == 0 %}{% set total_pages = 1 %}{% endif %}

{% set effective_from_wh = doc.from_warehouse %}
{% set effective_to_wh = doc.to_warehouse %}

{% if not effective_from_wh and doc.items %}
  {% set effective_from_wh = doc.items[0].s_warehouse %}
{% endif %}

{% if not effective_to_wh and doc.items %}
  {% set effective_to_wh = doc.items[0].t_warehouse %}
{% endif %}

{% for page in range(total_pages) %}

{% set start = page * items_per_page %}
{% set end = start + items_per_page %}
{% set page_items = doc.items[start:end] %}
{% set page_count = page_items|length %}

<div class="outer-box">

  {% if letter_head and not no_letterhead %}
  <div class="letter-head">
    {{ letter_head }}
  </div>
  {% endif %}

  <div class="content">

    <div class="stock-transfer-title">Stock Transfer</div>

    <table class="branch-info-section">
      <tr>
        <td class="branch-box">
          <div class="branch-label">FROM BRANCH</div>
          <div>{{ effective_from_wh or "" }}</div>
        </td>
        <td class="branch-box">
          <div class="branch-label">TO BRANCH</div>
          <div>{{ effective_to_wh or "" }}</div>
        </td>
        <td class="branch-box">
          <div class="info-row">
            <span class="info-label">Date:</span>
            <span>{{ doc.get_formatted("posting_date") }}</span>
          </div>
          <div class="info-row">
            <span class="info-label">Stock Transfer No:</span>
            <span>{{ doc.name }}</span>
          </div>
        </td>
      </tr>
    </table>

    <div class="items-title">Stock Transfer Details</div>

    <table class="items-table">
      <thead>
        <tr>
          <th style="width:40px;">Sr No</th>
          <th>Description</th>
          <th style="width:80px;">QTY</th>
          <th style="width:80px;">Unit</th>
        </tr>
      </thead>

      <tbody>

        {% for d in page_items %}
        <tr>
          <td class="text-center">{{ start + loop.index }}</td>
          <td>{{ d.item_name or d.item_code }}</td>
          <td class="text-center">{{ d.qty or 0 }}</td>
          <td class="text-center">{{ d.uom or "" }}</td>
        </tr>
        {% endfor %}

        {% for i in range(items_per_page - page_count) %}
        <tr>
          <td>&nbsp;</td>
          <td></td>
          <td></td>
          <td></td>
        </tr>
        {% endfor %}

      </tbody>
    </table>

  </div>

  {% if loop.last %}
  <div class="signature-fixed">
    For, JAIN MACHINE TOOLS & ELECTRICALS LLP
  </div>
  {% endif %}

  {% if footer and not no_letterhead %}
  <div class="print-footer">
    {{ footer }}
  </div>
  {% endif %}

</div>

{% endfor %}

