html:
{% set paper = namespace(show_base_price=false) %}

{% for row in doc.items %}
    {% set ns_record = frappe.get_all(
        "Non Standard Item Creation",
        filters={"new_item_code": row.description},
        fields=["base_price"],
        limit=1
    ) %}
    {% if ns_record %}
        {% set paper.show_base_price = true %}
    {% endif %}
{% endfor %}

<!-- ================= MACROS START ================= -->
<!-- MODIFIED HEADER MACRO: Accepts 'show_po_details' parameter -->
{% macro render_header(doc, show_po_details=True) %}
    <table style="width: 100%; font-family: 'Helvetica Neue', Arial, sans-serif; border-bottom: 1px solid #111;">
        <tr>
            <td style="width: 100%; vertical-align: top;">
                <img src="/files/JMT HEADER.png" style="width: 100%; height: 130px;">
            </td>
        </tr>
    </table>

    <!-- CONDITIONALLY RENDER PO DETAILS BLUE BAR -->
    <div style="text-align:center;background-color:#b6e1fb;">
        <span style="font-weight: bold!important;">
            TAX INVOICE 

        </span>
    </div>

    <table style="width:100%; border-collapse:collapse; font-family: Arial, sans-serif; font-size:10px;">
        <tr>
            <td style="width:35%; vertical-align:top; border:1px solid #000;">
                <table style="width:100%; border-collapse:collapse;font-size:10px">
                    <tr><td style="font-weight:bold; font-size:12px;">BILLING DETAILS</td></tr>
                    <tr><td><strong>Company Name:</strong> {{ doc.company or "" }}</td></tr>
                    <tr>
                        <td>
                            <strong>Address:</strong><br/>
                            {% if doc.company_address %}
                                <div>
                                {% set addr = frappe.get_doc("Address", doc.company_address) %}
                                {{ addr.address_line1 or "" }} , 
                                {% if addr.address_line2 %}{{ addr.address_line2 }} , {% endif %}
                                {{ addr.city or "" }} , 
                                {{ addr.state or "" }}{% if addr.pincode %} - {{ addr.pincode }}{% endif %}<br/>
                                </div>
                            {% endif %}
                        </td>
                    </tr>
                    <tr><td><strong>Contact Person:</strong> {{ doc.company_contact_person or "NIL" }}</td></tr>
                    <tr><td><strong>Contact No:</strong> {{ doc.contact_mobile or "" }}</td></tr>
                    <tr><td><strong>GST:</strong> {{ doc.company_gstin or "" }}</td></tr>
                </table>
            </td>
            <td style="width:35%; vertical-align:top; border-top:1px solid #000; border-bottom:1px solid #000; border-right:1px solid #000;">
                <table style="width:100%; border-collapse:collapse;font-size:10px">
                    <tr><td style="font-weight:bold; font-size:12px;">CONSIGNEE DETAILS</td></tr>
                    <tr><td><strong>Name:</strong> {{ doc.customer or "" }}</td></tr>
                    <tr>
                        <td>
                            <strong>Address:</strong><br/>
                            {% if doc.customer_address %}
                                <div>
                                {% set addr = frappe.get_doc("Address", doc.customer_address) %}
                                {{ addr.address_line1 or "" }} , 
                                {% if addr.address_line2 %}{{ addr.address_line2 }} , {% endif %}
                                {{ addr.city or "" }} , 
                                {{ addr.state or "" }}{% if addr.pincode %} - {{ addr.pincode }}{% endif %}<br/>
                                </div>
                            {% endif %}
                        </td>
                    </tr>
                    <tr><td><strong>Contact Person::</strong> {{ doc.contact_display or "" }}</td></tr>
                    <tr><td><strong>Contact No:</strong> {{ doc.contact_mobile or "" }}</td></tr>
                    <tr><td><strong>GST:</strong> {{ doc.company_gstin or "" }}</td></tr>
                </table>
            </td>
            {% set so_name = doc.items[0].sales_order if doc.items and doc.items[0].sales_order else None %}
            {% set so_doc = frappe.get_doc("Sales Order", so_name) if so_name else None %}
            <td style="width:30%; vertical-align:top; border:1px solid #000;">
                <table style="width:100%;border-collapse:collapse; font-size:10px;">
                    <tr style="border-bottom:1px solid #000;"><td style="border-right: 1px solid #000;"><strong>Invoice No:</strong></td><td>{{ doc.name }}</td></tr>
                    <tr style="border-bottom:1px solid #000;"><td style="border-right: 1px solid #000;"><strong>Invoice Date:</strong></td><td>{{ frappe.utils.formatdate(doc.posting_date, 'dd-MMM-yyyy') }}</td></tr>
                    <tr style="border-bottom:1px solid #000;"><td style="border-right: 1px solid #000;"><strong>PO No:</strong></td><td>{{ so_doc.po_no if so_doc and so_doc.po_no else "" }}</td></tr>
                    <tr style="border-bottom:1px solid #000;"><td style="border-right: 1px solid #000;"><strong>PO Date:</strong></td><td>{{ frappe.utils.formatdate(so_doc.transaction_date, 'dd-MMM-yyyy') if so_doc and so_doc.po_no and so_doc.transaction_date else "" }}</td></tr>
                    <tr style="border-bottom:1px solid #000;"><td style="border-right: 1px solid #000;"><strong>Payment Due Date:</strong></td><td>{{ frappe.utils.formatdate(doc.due_date, 'dd-MMM-yyyy') }}</td></tr>
                    <tr style="border-bottom:1px solid #000;"><td style="border-right: 1px solid #000;"><strong>Dispatch type:</strong></td><td>{{ doc.tc_name or " " }}</td></tr>
                    <tr><td style="border-right: 1px solid #000;"><br><br></td><td><br><br></td></tr>
                </table>
            </td>
        </tr>
    </table>
    <!-- CONDITIONALLY RENDER 'PO DETAILS' HEADER ONLY IF REQUESTED -->
    {% if show_po_details %}
    <div style="text-align:center;background-color:#b6e1fb;"><strong> TAX INVOICE DETAILS</strong></div>
    {% endif %}
{% endmacro %}

{% macro render_remarks_and_totals(doc) %}
<div style="padding-left:3px;padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span style="font-weight:bold;">Other Details:</span>
    {% if doc.terms %}
        {{ doc.terms }}
    {% endif %}
</div>
<table style ="width:100%; border-collapse:collapse;">
    <tr style="border-bottom:1px solid #111; text-align:left;font-size:11px;">
        <td style="width:70%;">
            <table style="width:100%; border-collapse:collapse; font-size:10px;">
                <span style="font-size:12px;"><strong>E-Invoice Details:</strong></span><br>
                <span style="font-size:10px;"><strong>IRN:</strong></span>{{ doc.irn or "" }}<br>
                <span style="font-size:10px;"><strong>QR Code Ack No:</strong></span>{{ doc.ack_no or "" }}<br>
                <span style="font-size:10px;"><strong>Ack Dt:</strong></span>{{ doc.get_formatted("ack_date") if doc.ack_date else "" }}<br><br>

                <span style="font-size:12px;"><strong>Dispatch Details:</strong></span><br>
                <span style="font-size:10px;"><strong>Order No:</strong></span><br>
                <span style="font-size:10px;"><strong>Dispatch From:</strong></span>{{ doc.dispatch_address_name or "" }}<br>
                <span style="font-size:10px;"><strong>Dispatch Type:</strong></span><br>
                <span style="font-size:10px;"><strong>Transporter Name:</strong></span><br>
                <span style="font-size:10px;"><strong>Freight:</strong></span><br>
                <span style="font-size:10px;"><strong>E-way Bill No:</strong></span><br>
                <span style="font-size:10px;"><strong>LR No:</strong></span><br>
            </table>
        </td>
        <td style="width:30%;vertical-align:top; border:1px solid #000;">
            <table style="width:100%;border-collapse:collapse; font-size:10px;">
                {% set cgst_rate = doc.cgst_rate or (doc.items | map(attribute='cgst_rate') | max) or 0 %}
                {% set sgst_rate = doc.sgst_rate or (doc.items | map(attribute='sgst_rate') | max) or 0 %}
                {% set igst_rate = doc.igst_rate or (doc.items | map(attribute='igst_rate') | max) or 0 %}
                {% set total_cgst = doc.cgst or doc.items | sum(attribute='cgst_amount') or 0 %}
                {% set total_sgst = doc.sgst or doc.items | sum(attribute='sgst_amount') or 0 %}
                {% set total_igst = doc.igst or doc.items | sum(attribute='igst_amount') or 0 %}
                {% set is_igst = total_igst > 0 %}

                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>Subtotal</strong></td>
                    <td>{{ frappe.format(doc.total,{"fieldtype":"Currency","options":doc.currency}) or "" }}</td>
                </tr>
                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong> Other Charges</strong></td>
                </tr>

                {% if not is_igst %}
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000;"><strong>CGST ({{ cgst_rate }}%)</strong></td>
                        <td>{% if total_cgst > 0 %} {{ frappe.format(total_cgst, {"fieldtype": "Currency", "options": doc.currency}) }} {% endif %}</td>
                    </tr>
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000;"><strong>SGST ({{ sgst_rate }}%)</strong></td>
                        <td>{% if total_sgst > 0 %} {{ frappe.format(total_sgst, {"fieldtype": "Currency", "options": doc.currency}) }} {% endif %}</td>
                    </tr>
                {% else %}
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000;"><strong>IGST ({{ igst_rate }}%)</strong></td>
                        <td>{% if total_igst > 0 %} {{ frappe.format(total_igst, {"fieldtype": "Currency", "options": doc.currency}) }} {% endif %}</td>
                    </tr>
                {% endif %}

                <tr style="border-bottom:1px solid #000;">
                    {% set ns = namespace(disc_amt=0, disc_pct=0) %}
                    {% for i in doc.items %}
                        {% if i.discount_percentage and i.price_list_rate %}
                            {% set ns.disc_amt = ns.disc_amt + ((i.price_list_rate * i.discount_percentage / 100) * i.qty) %}
                            {% set ns.disc_pct = ns.disc_pct + i.discount_percentage %}
                        {% endif %}
                    {% endfor %}
                    <td style="border-right: 1px solid #000;"><strong> Discount {% if ns.disc_pct %} ({{ ns.disc_pct }}%) {% endif %} </strong></td>
                    <td> {{ frappe.format( ns.disc_amt, {"fieldtype":"Currency","options":doc.currency} ) }} </td>
                </tr>
                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>TCS</strong></td>
                    <td> {{ frappe.format(doc.tcs_amount or 0, {"fieldtype":"Currency","options":doc.currency}) }} </td>
                </tr>
                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>Round Off</strong></td>
                    <td> {{ frappe.format(doc.rounding_adjustment or 0, {"fieldtype":"Currency","options":doc.currency}) }} </td>
                </tr>
                <tr>
                    <td style="border-right: 1px solid #000;"><strong>Total Amt</strong></td>
                    <td> {{ frappe.format(doc.rounded_total or 0, {"fieldtype":"Currency","options":doc.currency}) }} </td>
                </tr>
            </table>
        </td>
    </tr>
</table>

<div style="padding-left:3px; padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span style="font-weight:bold;">Total Amount (In words):</span> {{ doc.in_words }}
</div>
<div style="padding-left:3px; padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span>Our risk and responsibility cease on the delivery of the goods on transport.All the disputes under this bill will be settelled in the Mumbai Jurisdiction.
</span>
</div>
<div style="padding-left:3px; padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span>We hereby certify that our Registration Certificate under the Goods and Services Tax Act, 2017 is in force on the date on which the sale of the goods specified in this GST Invoice has been affected by us. This
transaction of sale cover by "GST Invoice" has effected by us and it shall be accounted for in the turnover of sales while filling of return and the due tax, if any, payable on the sale has been paid or shall be paid.
</span>
</div>

{% set approved_user = frappe.db.get_value("Workflow Action", {"reference_name": doc.name, "completed_by_role": "Purchase Manager", "status": "Completed"}, "completed_by", order_by="creation desc") %}
<table style="width: 100%; font-family: 'Helvetica Neue', Arial, sans-serif; border-bottom: 1px solid #111;">
    <tr>
        <td style="width:40%; height:180px; position: relative;">
            <table style="width:100%; font-size:10px; position:absolute; bottom:5px; top:5px;">
                {% set company_dets = frappe.get_doc("Company", doc.company) %}
                <tr>
                <td><b>GSTIN-{{ company_dets.gstin or " " }}</b></td><br>
                </tr>
                <tr>
                <td><b>PAN No-{{ company_dets.pan or " " }}</b></td><br>
                </tr>
                <tr>
                <td><b>BANK DETAILS-</b></td><br>
                </tr>
                {% set bank_dets = frappe.get_list("Bank Account" , filters={"company": doc.company}, fields="name") %}
                {% set bank_detailed_record = frappe.get_doc("Bank Account" , bank_dets[0].name) %}
                <tr>
                <td>BANK NAME:-{{ bank_detailed_record.bank }}</td><br>
                </tr>
                <tr>
                <td>ACCOUNT NO:-{{ bank_detailed_record.bank_account_no }}</td><br>
                </tr>
                <tr>
                <td>BANK BRANCH:-{{ bank_detailed_record.branch_code }}</td><br>
                </tr>
                <tr>
                <td>RTGS/NEFT IFSC CODE:-{{ bank_detailed_record.custom_ifsc_code or "BARB0MULUND" }}</td><br>
                </tr>
                <tr>
                <td>RTGS/NOTE:-Please treat the 5th article as number "0" in RTGS code</td><br>
                </tr>

            </table>
        </td>
        <td style="width:30%; border-left: 1px solid #000; height:120px; font-size:10px; text-align:center;">
