{# Use Namespace to prevent scope issues (Duplicates Fix) #}
{% set ns = namespace(current_page=[], current_height=0, all_pages=[]) %}

{# Settings #}
{% set max_lines = 39 %}
{# Padding = 2 ensures Last Item travels with Total Row if space is tight #}
{% set total_row_padding = 1 %} 

{% for item in doc.items %}
    {# 1. Calculate how many visual lines this item takes #}
    {% set newlines = ((item.description or "")|string).count('\n') %}
    {% set wraps = (((item.description or "")|length) / 50) | int %}
    {% set lines = 1 + newlines + wraps %}

    {# 2. Check if this is the VERY LAST item #}
    {% set effective_lines = lines %}
    {% if loop.last %}
        {# If last item, pretend it is taller to check if Total Row fits #}
        {% set effective_lines = lines + total_row_padding %}
    {% endif %}

    {# 3. Overflow Check #}
    {% if (ns.current_height + effective_lines) > max_lines %}
        {# Page Full: Save current page, Start new page with this item #}
        {% set _ = ns.all_pages.append(ns.current_page) %}
        {% set ns.current_page = [item] %}
        {% set ns.current_height = lines %} 
    {% else %}
        {# Page Fits: Add item #}
        {% set _ = ns.current_page.append(item) %}
        {% set ns.current_height = ns.current_height + lines %}
    {% endif %}

{% endfor %}

{# 4. Add the final leftover page #}
{% if ns.current_page %}
    {% set _ = ns.all_pages.append(ns.current_page) %}
{% endif %}

{# 5. Determine if Remarks need to move to a separate page #}
{# Check the height of the LAST page generated #}
{% set last_page_items = ns.all_pages[-1] %}
{% set ns_last = namespace(h=0) %}
{% for i in last_page_items %}
    {% set nl = ((i.description or "")|string).count('\n') %}
    {% set wr = (((i.description or "")|length) / 50) | int %}
    {% set ns_last.h = ns_last.h + 1 + nl + wr %}
{% endfor %}
{# If last page + total row > 14 (approx half page), move remarks #}
{% set move_remarks = (ns_last.h + total_row_padding) > 14 %}


