                        <th width="10%"><strong>Net Amount</strong></th>
                    </tr>
                </thead>
                <tbody>
                    {% for row in batch %}
                    {% set sr_no.val = sr_no.val + 1 %}
                    <tr style="font-size:10px; border-bottom:1px solid #000;">
                        <td style="text-align:center; border-right:1px solid #000;">{{ sr_no.val }}</td>
                        <td style="text-align:center;border-right:1px solid #000; white-space: pre-wrap;">{{ row.description }}</td>
                        <td style="text-align:center;border-right:1px solid #000; white-space: nowrap;">{{ row.gst_hsn_code or "" }}</td>
                        <td style="text-align:center;border-right:1px solid #000; white-space: nowrap;">{{ "%.2f"|format(row.rate or 0) }}</td>
                        {% set ns_record = frappe.get_all(
                            "Non Standard Item Creation",
                            filters={"new_item_code": row.description},
                            fields=["base_price"],
                            limit=1
                        ) %}

                        {% if paper.show_base_price %}
                        <td style="text-align:center;border-right:1px solid #000; white-space: nowrap;">
                            {% if ns_record %}
                                {{ "%.2f"|format(ns_record[0].base_price or 0) }}
                            {% endif %}
                        </td>
                        {% endif %}
                        <td style="text-align:center;border-right:1px solid #000;">{{ row.qty or 0 }}</td>
                        <td style="text-align:center;border-right:1px solid #000;">{{ "%.2f"|format(row.discount_percentage or 0) }}</td>
                        <td style="text-align:center;border-right:1px solid #000;">{{ "%.2f"|format(row.handling_charges_value or 0) }}</td>
                        <td style="text-align:center; white-space: nowrap;">{{ "%.2f"|format(row.amount or 0) }}</td>
                    </tr>
                    {% endfor %}

                    {# Total Row Logic #}
                    {% if is_last_page %}
                    <tr style="font-weight:bold; font-size:11px; background-color:#b6e1fb;">
                        <td colspan="2" style="border:1px solid #111; text-align:left; padding-left:5px;"> Total </td>
                        <td style="border:1px solid #111;"></td>
                        <td style="border:1px solid #111;"></td>
                        {% if paper.show_base_price %}
                            <td style="border:1px solid #111;"></td>
                          {% endif %}
                        <td style="border:1px solid #111; text-align:center;"> {{ doc.items | sum(attribute='qty') }} </td>
                        <td style="border:1px solid #111;"></td>
                        <td style="border:1px solid #111; text-align:center;"></td>
                        <td style="border:1px solid #111; text-align:center; vertical-align: middle;">
                            <div style="line-height: 1; white-space: nowrap;">
                                <span style="font-weight: bold; font-size: 10px;">{{ frappe.format(doc.items | sum(attribute='net_amount'), {"fieldtype":"Currency", "options": doc.currency}) }}</span>
                            </div>
                        </td>
                    </tr>
                    {% endif %}
                </tbody>
            </table>

            {% if is_last_page and not move_remarks %}
                {{ render_remarks_and_totals(doc) }}
            {% endif %}
        </div>

        <div class="footer-wrapper">
            <img src="/files/JMT FOOTER.png" style="width: 100%; height: 60px; display: block;">
        </div>
    </div> 

    {# Separate Remarks Page if needed #}
    {% if is_last_page and move_remarks %}
    <div class="header-above-container">
        <div class="left"> {{ doc.name }} </div>
        <div class="right"> {{ frappe.utils.formatdate(doc.posting_date, "dd-MMM-yyyy") }} </div>
    </div> 
    <div class="spring-container">
        <div class="content-wrapper">
            <!-- Remarks only page gets NO blue bar -->
            {{ render_header(doc, show_po_details=False) }}
            <div style="margin-top: 0px;">
                {{ render_remarks_and_totals(doc) }}
            </div>
        </div>
        <div class="footer-wrapper">
            <img src="/files/JMT FOOTER.png" style="width: 100%; height: 60px; display: block;">
        </div>
    </div>
    {% endif %}

{% endfor %}

