}

.invoice-details-table td {
    padding: 3px 0;
    font-size: 8pt;
}

.invoice-details-table tr {
    border-bottom: 1px solid #000;
}

.invoice-details-table tr:last-child {
    border-bottom: none;
}

.invoice-label {
    font-weight: normal;
    width: 110px;
    border-right: 1px solid #000;
}

.invoice-value {
    font-weight: normal;
