    width: 100%;
    border-collapse: collapse;
}

.items-table th,
.items-table td {
    border: 1px solid #000;
    padding: 4px;
    font-size: 8pt;
    text-align: left;
}

.items-table th {
    background: #f0f0f0;
    font-weight: bold;
    text-align: center;
}

.items-table td {
    vertical-align: top;
}

.text-center {
    text-align: center !important;
}

.text-right {
    text-align: right !important;
}

/* Transport and totals section */
.bottom-section {
    display: flex;
    border-bottom: 1px solid #000;
}

.transport-details {
    flex: 1;
    padding: 8px;
