.footer-section {
    display: flex;
    border: 1px solid #000;
}

.bank-details {
    flex: 1;
    padding: 5px;
    font-size: 8pt;
    border-right: 1px solid #000;
}

.signature-section {
    width: 220px;
    padding: 8px;
    text-align: center;
}

.signature-box {
    margin-top: 40px;
    padding-top: 8px;
    border-top: 1px solid #000;
}

.company-footer {
    font-weight: bold;
    font-size: 9pt;
    margin-bottom: 20px;
}

