/* Barcode Print Format Styles */
@page {
  size: A4 portrait;
  margin: 8mm 0;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Arial', 'Helvetica', sans-serif;
  margin: 0;
  padding: 0;
}

.barcode-page {
  width: 100%;
  page-break-after: always;
  page-break-inside: avoid;
}

.barcode-page:last-child {
  page-break-after: avoid;
}

.barcode-grid {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  align-content: flex-start;
  width: 100%;
  gap: 0;
}

.barcode-item {
  width: 10.5cm;
  height: 7.5cm;
  border: 1.5px solid #555;
  border-radius: 3px;
  padding: 2mm 3mm;
  text-align: center;
  background: #ffffff;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  align-items: center;
  page-break-inside: avoid;
}

.logo-container {
  width: 100%;
  text-align: center;
  padding-bottom: 1mm;
  border-bottom: 1px solid #e0e0e0;
  margin-bottom: 1mm;
}

.sticker-logo {
  max-width: 70px;
  max-height: 20px;
  height: auto;
  display: inline-block;
}

.brand-name {
  font-size: 11pt;
  font-weight: bold;
  color: #222;
  letter-spacing: 0.3px;
  width: 100%;
  text-align: center;
  margin: 1mm 0;
}

.barcode-wrapper {
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  flex: 1;
  background: #fff;
}

.barcode-wrapper img {
  max-width: 90%;
  max-height: 32mm;
  height: auto;
  display: block;
}

.item-info {
  width: 100%;
  border-top: 1px solid #ddd;
  padding-top: 1.5mm;
  margin-top: 1mm;
}

.serial-no {
  font-size: 11pt;
  font-weight: bold;
  color: #000;
  word-break: break-all;
  line-height: 1.2;
  margin-bottom: 0.5mm;
  letter-spacing: 0.2px;
}

.item-code {
  font-size: 9pt;
  color: #555;
  font-weight: normal;
  margin-top: 0.5mm;
}

.empty-placeholder {
  border: 1.5px dashed #ccc;
  background: #f9f9f9;
  color: #999;
  font-size: 9pt;
  font-style: italic;
}

@media print {
  .barcode-page {
    page-break-after: always;
    page-break-inside: avoid;
  }

  .barcode-page:last-child {
    page-break-after: avoid;
  }

  .barcode-item {
    page-break-inside: avoid;
  }
}

html:
{% set items = doc.table_hjbk %}
{% set total_items = items|length %}
{% set items_per_page = 4 %}
{% set total_pages = ((total_items - 1) // items_per_page) + 1 if total_items > 0 else 1 %}

{% for page_num in range(total_pages) %}
  <div class="barcode-page">
    <div class="barcode-grid">
      {% set start_idx = page_num * items_per_page %}
      {% set end_idx = start_idx + items_per_page %}

      {% for i in range(start_idx, end_idx) %}
        {% if i < total_items %}
          {% set item = items[i] %}
          {% set brand = frappe.db.get_value("Item", item.item_code, "brand") if item.item_code else "" %}
          <div class="barcode-item">
            <!-- Company Logo -->
            <div class="logo-container">
              <img src="/assets/jain_machine_tools/images/JMT LOGO.png" class="sticker-logo" alt="JMT" />
            </div>

            <!-- Brand Name -->
            {% if brand %}
              <div class="brand-name">{{ brand }}</div>
            {% endif %}

            <!-- Barcode -->
            <div class="barcode-wrapper">
              {% set barcode_img = get_barcode_image(item.serial_no or "NO-SERIAL") %}
              {% if barcode_img %}
                <img src="{{ barcode_img }}" alt="{{ item.serial_no }}" />
              {% else %}
                <div style="padding: 10px; background: #f8f8f8; border: 1px solid #ddd; border-radius: 3px; font-size: 9pt;">
                  Barcode Failed
                </div>
              {% endif %}
            </div>

            <!-- Serial Number & Item Code -->
            <div class="item-info">
              <div class="serial-no">{{ item.serial_no or "NO-SERIAL" }}</div>
              {% if item.item_code %}
                <div class="item-code">{{ item.item_code }}</div>
              {% endif %}
            </div>
          </div>
        {% else %}
          <div class="barcode-item empty-placeholder">
            <div style="display: flex; align-items: center; justify-content: center; height: 100%;">
              <span>-</span>
            </div>
          </div>
        {% endif %}
      {% endfor %}
    </div>
  </div>
{% endfor %}

css:
th { color: #111 !important; font-weight: 500 !important; }
.print-format td, .print-format th { padding: 2px !important; }
.tab_label { font-size: 11px !important; vertical-align: baseline !important; font-weight: bold; }
.print-format th { border-bottom: 1px solid #111 !important; }
.print-format td { vertical-align: baseline !important; }
.item_tab thead th, .tax_tab thead th { font-weight: bold !important; text-align: center; vertical-align: middle !important; }
.items-table { width: 100%; border-collapse: collapse; }
