/* MAIN LAYOUT CSS */
.spring-container {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    border: 2px solid #111 !important;
    min-height: 280mm;
    height: auto;
    box-sizing: border-box;
    margin-bottom: 2mm;
    position: relative;
    background-color: white;
}
.content-wrapper {
    flex-grow: 1;
    display: flex;
    flex-direction: column;
}
.footer-wrapper {
    flex-shrink: 0;
    width: 100%;
    margin-top: auto;
    border-top: 1px solid #111;
}
@page {
    size: A4;
    margin: 4.5mm;
    @bottom-center {
        content: "Page " counter(page) " of " counter(pages);
        font-size: 9px;
        color: #555;
        margin-bottom: 7mm;
    }
}
