<!-- ================= FIXED LOGIC ================= -->
{% set ns = namespace(current_page=[], current_height=0, all_pages=[]) %}
{% set max_lines = 39 %}
{% set total_row_padding = 1 %}
{% for item in doc.items %}
    {% set newlines = ((item.description or "")|string).count('\n') %}
    {% set wraps = (((item.description or "")|length) / 50) | int %}
    {% set sn_lines = 1 if item.serial_no else 0 %}
    {% set lines = 1 + newlines + wraps + sn_lines %}
    {% set effective_lines = lines %}
    {% if loop.last %}
        {% set effective_lines = lines + total_row_padding %}
    {% endif %}
    {% if (ns.current_height + effective_lines) > max_lines %}
        {% set _ = ns.all_pages.append(ns.current_page) %}
        {% set ns.current_page = [item] %}
        {% set ns.current_height = lines %}
    {% else %}
        {% set _ = ns.current_page.append(item) %}
        {% set ns.current_height = ns.current_height + lines %}
    {% endif %}
{% endfor %}
{% if ns.current_page %}
    {% set _ = ns.all_pages.append(ns.current_page) %}
{% endif %}

{% set last_page_items = ns.all_pages[-1] %}
{% set ns_last = namespace(h=0) %}
{% for i in last_page_items %}
    {% set nl = ((i.description or "")|string).count('\n') %}
    {% set wr = (((i.description or "")|length) / 50) | int %}
    {% set snl = 1 if i.serial_no else 0 %}
    {% set ns_last.h = ns_last.h + 1 + nl + wr + snl %}
{% endfor %}
{% set move_remarks = (ns_last.h + total_row_padding) > 14 %}

<!-- ================= RENDERING ================= -->
{% if doc.workflow_state == "Rejected" or doc.workflow_state != "Approved" %}
<div class="po-watermark"></div>
{% endif %}

{% set sr_no = namespace(val=0) %}
{% for batch in ns.all_pages %}
    {% set is_last_page = loop.last %}

    <div class="header-above-container">
        <div class="left"> {{ doc.name }} </div>
        <div class="right"> {{ frappe.utils.formatdate(doc.posting_date, "dd-MMM-yyyy") }} </div>
    </div>
    <div class="spring-container {% if not is_last_page or move_remarks %}page-break{% endif %}">

        <div class="content-wrapper">
            {{ render_header(doc, show_po_details=True) }}
            <table class="items-table" style="width:100%; border-bottom:1px solid #000;border-top:1px solid #000;">
                <thead>
                    <tr style="font-weight:bold; font-size:11px;">
                        <th width="5%" style="border-right:1px solid #000; text-align:center;"><strong>Sr. No.</strong></th>
                        <th width="40%" style="border-right:1px solid #000; text-align:center;"><strong>Description</strong></th>
                        <th width="10%" style="border-right:1px solid #000; text-align:center;"><strong>HSN Code</strong></th>
                        <th width="10%" style="border-right:1px solid #000; text-align:center;"><strong>Unit Rate</strong></th>
                        {% if paper.show_base_price %}
                            <th width="10%;" style="border-right:1px solid #000; text-align:center;"><strong>Base Price</strong></th>
                        {% endif %}
                        <th width="7%" style="border-right:1px solid #000; text-align:center;"><strong>Qty</strong></th>
                        <th width="10%" style="border-right:1px solid #000; text-align:center;"><strong>Handling Charges</strong></th>
                        <th width="10%" syle="text-align:center;"><strong>Net Amount</strong></th>
                    </tr>
                </thead>
                <tbody>
                    {% for row in batch %}
                    {% set sr_no.val = sr_no.val + 1 %}
                    <tr style="font-size:10px; border-bottom:1px solid #000; vertical-align: top;">
                        <td style="text-align:center; border-right:1px solid #000; padding-top:5px;">{{ sr_no.val }}</td>

                        <td style="border-right:1px solid #000; padding: 5px; text-align: left;">
                            <div style="white-space: pre-wrap;">{{ row.description }}</div>
                            {% if row.serial_no %}
                                <div style="font-size: 9px; color: #333; margin-top: 4px; text-align: left;">
                                    <strong>Serial No:</strong> {{ row.serial_no | replace("\n", ", ") | replace("\r", "") }}
                                </div>
                            {% endif %}
                        </td>

                        <td style="text-align:center;border-right:1px solid #000; white-space: nowrap; padding-top:5px;">{{ row.gst_hsn_code or "" }}</td>
                        <td style="text-align:right;border-right:1px solid #000; white-space: nowrap; padding-top:5px;">
                            {{ frappe.format(row.rate, {"fieldtype": "Currency", "options": doc.currency}) }}</td>

                        {% if paper.show_base_price %}
                        <td style="text-align:center;border-right:1px solid #000; white-space: nowrap; padding-top:5px;">
                            {% set ns_record = frappe.get_all("Non Standard Item Creation", filters={"new_item_code": row.description}, fields=["base_price"], limit=1) %}
                            {% if ns_record %} {{ "%.2f"|format(ns_record[0].base_price or 0) }} {% endif %}
                        </td>
                        {% endif %}

                        <td style="text-align:center;border-right:1px solid #000; padding-top:5px;">{{ row.qty|int or 0 }}</td>
                        <td style="text-align:right;border-right:1px solid #000; padding-top:5px;">{{ "%.2f"|format(row.handling_charges_value or 0) }}</td>
                        <td style="text-align:right; white-space: nowrap; padding-top:5px;">
                            {{ frappe.format(row.amount, {"fieldtype": "Currency", "options": doc.currency}) }}</td>
                    </tr>
                    {% endfor %}
                    {% if is_last_page %}
                    <tr style="font-weight:bold; font-size:11px; background-color:#b6e1fb;">
                        <td colspan="2" style="border:1px solid #111; text-align:left; padding-left:5px;"> Total </td>
                        <td style="border:1px solid #111;"></td>
                        <td style="border:1px solid #111;"></td>
                        {% if paper.show_base_price %}
                            <td style="border:1px solid #111;"></td>
                        {% endif %}
                        <td style="border:1px solid #111; text-align:center;"> {{ doc.items | sum(attribute='qty')|int }} </td>
                        <td style="border:1px solid #111; text-align:center;"></td>
                        <td style="border:1px solid #111; text-align:center; vertical-align: middle;">
                            <div style="line-height: 1; white-space: nowrap;">
                                <span style="font-weight: bold; font-size: 10px; text-align:right">{{ frappe.format(doc.items | sum(attribute='net_amount'), {"fieldtype":"Currency", "options": doc.currency}) }}</span>
                            </div>
                        </td>
                    </tr>
                    {% endif %}
                </tbody>
            </table>
            {% if is_last_page and not move_remarks %}
                {{ render_remarks_and_totals(doc) }}
            {% endif %}
        </div>
        <div class="footer-wrapper">
            <img src="/files/JMT FOOTER.png" style="width: 100%; height: 60px; display: block;">
        </div>
    </div>

    {% if is_last_page and move_remarks %}
    <div class="header-above-container">
        <div class="left"> {{ doc.name }} </div>
        <div class="right"> {{ frappe.utils.formatdate(doc.posting_date, "dd-MMM-yyyy") }} </div>
    </div>
    <div class="spring-container">
        <div class="content-wrapper">
            {{ render_header(doc, show_po_details=False) }}
            <div style="margin-top: 0px;">
                {{ render_remarks_and_totals(doc) }}
            </div>
        </div>
        <div class="footer-wrapper">
            <img src="/files/JMT FOOTER.png" style="width: 100%; height: 60px; display: block;">
        </div>
    </div>
    {% endif %}
{% endfor %}

css:
th { color: #111 !important; font-weight: 500 !important; }
.print-format td, .print-format th { padding: 2px !important; }
.tab_label { font-size: 11px !important; vertical-align: baseline !important; font-weight: bold; }
.print-format th { border-bottom: 1px solid #111 !important; }
.print-format td { vertical-align: baseline !important; }
.item_tab thead th, .tax_tab thead th { font-weight: bold !important; text-align: center; vertical-align: middle !important; }
.items-table { width: 100%; border-collapse: collapse; }
.items-table thead { display: table-header-group; }
.items-table tbody tr { page-break-inside: avoid; }
.po-watermark { position: fixed; top: 30%; left: 0; width: 100%; text-align: center; font-size: 100px; font-weight: bold; color: rgba(200, 0, 0, 0.1); transform: rotate(-30deg); z-index: 9999; pointer-events: none; }
.spring-container {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    border: 2px solid #111 !important;
    min-height: 280mm;
    height: auto;
    box-sizing: border-box;
    margin-bottom: 2mm;
    position: relative;
    background-color: white;
}
/* This more specific selector overrides the global baseline !important */
table tr td.qr-cell-container {
    vertical-align: middle !important;
    padding-top: 15px !important;
    padding-bottom: 15px !important;
    text-align: center !important;
}
    .content-wrapper {
    flex-grow: 1;
    display: flex;
    flex-direction: column;
}
.footer-wrapper {
    flex-shrink: 0;
    width: 100%;
    margin-top: auto;
    border-top: 1px solid #111;
}
@page {
    size: A4;
    margin: 4.5mm;
    @bottom-center {
        content: "Page " counter(page) " of " counter(pages);
        font-size: 9px;
        color: #555;
        margin-bottom: 7mm;
    }
}
.page-break {
    page-break-after: always;
}
.header-above-container {
    width: 100%;
    height: 15px;
    margin-bottom: 1px;
    font-size: 12px;
    font-weight: bold;
    overflow: hidden;
}
.header-above-container .left { float: left; }
.header-above-container .right { float: right; }

html:
{% set paper = namespace(show_base_price=false) %}
{% for row in doc.items %}
    {% set ns_record = frappe.get_all("Non Standard Item Creation", filters={"new_item_code": row.description}, fields=["base_price"], limit=1) %}
    {% if ns_record %}
        {% set paper.show_base_price = true %}
    {% endif %}
{% endfor %}

<!-- ================= MACROS START ================= -->
{% macro render_header(doc, show_po_details=True) %}
    <table style="width: 100%; font-family: 'Helvetica Neue', Arial, sans-serif; border-bottom: 1px solid #111;">
        <tr>
            <td style="width: 100%; vertical-align: top;">
                <img src="/files/JMT HEADER.png" style="width: 100%; height: 130px;">
            </td>
        </tr>
    </table>

    <div style="text-align:center;background-color:#b6e1fb;">
        <span style="font-weight: bold!important;">
            E-INVOICE / TAX INVOICE
        </span>
    </div>

    {% set contact_doc = frappe.get_doc("Contact", doc.contact_person) if doc.contact_person else None %}
    {% set contact_phone = contact_doc.phone_nos[0].phone if contact_doc and contact_doc.phone_nos else "" %}

    <table style="width:100%; border-collapse:collapse; font-family: Arial, sans-serif; font-size:10px;">
        <tr>
            <td style="width:35%; vertical-align:top; border:1px solid #000;">
                <table style="width:100%; border-collapse:collapse;font-size:10px">
                    <tr><td style="font-weight:bold; font-size:12px;">BILLING DETAILS</td></tr>
                    <tr><td><strong>Company Name:</strong> {{ doc.customer or "" }}</td></tr>
                    <tr>
                        <td>
                            <strong>Address:</strong><br/>
                            {% if doc.customer_address %}
                                <div>
                                {% set addr = frappe.get_doc("Address", doc.customer_address) %}
                                {{ addr.address_line1 or "" }} ,
                                {% if addr.address_line2 %}{{ addr.address_line2 }} , {% endif %}
                                {{ addr.city or "" }} ,
                                {{ addr.state or "" }}{% if addr.pincode %} - {{ addr.pincode }}{% endif %}<br/>
                                </div>
                            {% endif %}
                        </td>
                    </tr>
                    <tr><td><strong>Contact Person:</strong> {{ doc.contact_display or "NIL" }}</td></tr>
                    <tr><td><strong>Contact No:</strong> {{ contact_phone }}</td></tr>
                    <tr><td><strong>GST:</strong> {{ doc.billing_address_gstin or "" }}</td></tr>
                </table>
            </td>

            <td style="width:35%; vertical-align:top; border-top:1px solid #000; border-bottom:1px solid #000; border-right:1px solid #000;">
                <table style="width:100%; border-collapse:collapse;font-size:10px">
                    <tr><td style="font-weight:bold; font-size:12px;">CONSIGNEE DETAILS</td></tr>
                    <tr><td><strong>Name:</strong> {{ doc.customer or "" }}</td></tr>
                    <tr>
                        <td>
                            <strong>Address:</strong><br/>
                            {% if doc.shipping_address_name %}
                                <div>
                                {% set s_addr = frappe.get_doc("Address", doc.shipping_address_name) %}
                                {{ s_addr.address_line1 or "" }} ,
                                {% if s_addr.address_line2 %}{{ s_addr.address_line2 }} , {% endif %}
                                {{ s_addr.city or "" }} ,
                                {{ s_addr.state or "" }}{% if s_addr.pincode %} - {{ s_addr.pincode }}{% endif %}<br/>
                                </div>
                            {% else %}
                                <div>{{ doc.shipping_address_display or "" }}</div>
                            {% endif %}
                        </td>
                    </tr>
                    <tr><td><strong>Contact Person::</strong> {{ doc.contact_display or "" }}</td></tr>
                    <tr><td><strong>Contact No:</strong> {{ contact_phone }}</td></tr>
                    <tr><td><strong>GST:</strong> {{ doc.billing_address_gstin or "" }}</td></tr>
                </table>
            </td>

            {% set so_name = doc.items[0].sales_order if doc.items and doc.items[0].sales_order else None %}
            {% set so_doc = frappe.get_doc("Sales Order", so_name) if so_name else None %}
            <td style="width:30%; vertical-align:top; border:1px solid #000; border-bottom:1px solid #000; padding: 0;">
                <table style="width:100%; border-collapse:collapse; font-size:10px; height: 100%;">
                    {# Removed the padding and added fixed height to help lines meet #}
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000; padding: 2px; width: 40%;"><strong>Invoice No:</strong></td>
                        <td style="padding: 2px;">{{ doc.name }}</td>
                    </tr>
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000; padding: 2px;"><strong>Invoice Date:</strong></td>
                        <td style="padding: 2px;">{{ frappe.utils.formatdate(doc.posting_date, 'dd-MMM-yyyy') }}</td>
                    </tr>
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000; padding: 2px;"><strong>PO No:</strong></td>
                        <td style="padding: 2px;">{{ so_doc.po_no if so_doc and so_doc.po_no else "" }}</td>
                    </tr>
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000; padding: 2px;"><strong>PO Date:</strong></td>
                        <td style="padding: 2px;">{{ frappe.utils.formatdate(so_doc.transaction_date, 'dd-MMM-yyyy') if so_doc and so_doc.po_no and so_doc.transaction_date else "" }}</td>
                    </tr>
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000; padding: 2px;"><strong>Payment Due Date:</strong></td>
                        <td style="padding: 2px;">{{ frappe.utils.formatdate(doc.due_date, 'dd-MMM-yyyy') }}</td>
                    </tr>
                    {# This row ensures the vertical line reaches the bottom of the outer border #}
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000; padding: 2px;"><strong>Dispatch type:</strong></td>
                        <td style="padding: 2px;">{{ doc.tc_name or " " }}</td>
                    </tr>
                </table>
            </td>
        </tr>
    </table>

    {% if show_po_details %}
    <div style="text-align:center;background-color:#b6e1fb;"><strong> E-INVOICE DETAILS</strong></div>
    {% endif %}
{% endmacro %}

{% macro render_remarks_and_totals(doc) %}
<!-- ================= E-INVOICE LOG SE DATA FETCH (Exact fields) ================= -->
{% set irn = doc.irn or "" %}
{% set ack_no = "" %}
{% set ack_date = "" %}

{% if doc.irn %}
    {# 2. Fetch the Log Document using the ID stored in the Invoice #}
    {% set einv_log = frappe.get_doc("e-Invoice Log", doc.irn) %}

    {% if einv_log %}
        {# 3. Directly access the fields from the Log #}
        {% set ack_no = einv_log.acknowledgement_number or "" %}

        {# Format the date to be readable #}
        {% if einv_log.acknowledged_on %}
            {% set ack_date = frappe.utils.format_datetime(einv_log.acknowledged_on, "dd-MM-yyyy HH:mm:ss") %}
        {% endif %}

        {# Fallback for IRN #}
        {% set irn = irn or einv_log.irn or "" %}
    {% endif %}
{% endif %}
<!-- ================= END FETCH ================= -->

<div style="padding-left:3px;padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span style="font-weight:bold;">Other Details:</span>
    {% if doc.terms %}{{ doc.terms }}{% endif %}
</div>

<table style ="width:100%; border-collapse:collapse;">
    <tr style="border-bottom:1px solid #111; text-align:left;font-size:11px;">
        <td style="width:70%;">
            <table style="width:100%; border-collapse:collapse; font-size:10px;">
                <tr style="background-color:#b6e1fb;">
                    <td><strong>E-INVOICE DETAILS</strong></td>
                </tr>
                <tr><td><strong>IRN:</strong> {{ irn }}</td></tr>
                <tr><td><strong>Ack No:</strong> {{ ack_no }}</td></tr>
                <tr><td><strong>Ack Date:</strong> {{ ack_date }}</td></tr>

                <tr style="height:15px;"></tr>

                <tr style="background-color:#b6e1fb;">
                    <td><strong>DISPATCH DETAILS</strong></td>
                </tr>
                <tr><td><strong>Order No:</strong> {{ doc.name }}</td></tr>
                <tr><td><strong>Dispatch From:</strong> {{ doc.dispatch_address_name or "" }}</td></tr>
                <tr><td><strong>Dispatch Type:</strong> {{ doc.tc_name or "" }}</td></tr>
                <tr><td><strong>Transporter Name:</strong> {{ doc.transporter_name or "" }}</td></tr>
                <tr><td><strong>Freight:</strong> {{ doc.freight or "" }}</td></tr>
                <tr><td><strong>E-way Bill No:</strong> {{ doc.ewaybill or "" }}</td></tr>
                <tr><td><strong>LR No:</strong> {{ doc.lr_no or "" }}</td></tr>
            </table>
        </td>

        <td style="width:30%; vertical-align:top; border:1px solid #000; padding:0;">
            <table style="width:100%; border-collapse:collapse; font-size:10px;">
                {% set cgst_rate = doc.cgst_rate or (doc.items | map(attribute='cgst_rate') | max) or 0 %}
                {% set sgst_rate = doc.sgst_rate or (doc.items | map(attribute='sgst_rate') | max) or 0 %}
                {% set igst_rate = doc.igst_rate or (doc.items | map(attribute='igst_rate') | max) or 0 %}
                {% set total_cgst = doc.cgst or doc.items | sum(attribute='cgst_amount') or 0 %}
                {% set total_sgst = doc.sgst or doc.items | sum(attribute='sgst_amount') or 0 %}
                {% set total_igst = doc.igst or doc.items | sum(attribute='igst_amount') or 0 %}
                {% set is_igst = total_igst > 0 %}

                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>Subtotal</strong></td>
                    <td style="text-align:right">{{ frappe.format(doc.total,{"fieldtype":"Currency","options":doc.currency}) or "" }}</td>
                </tr>
                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong> Other Charges</strong></td>
                </tr>
                {% if not is_igst %}
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000;"><strong>CGST ({{ cgst_rate }}%)</strong></td>
                        <td style="text-align:right">{% if total_cgst > 0 %} {{ frappe.format(total_cgst, {"fieldtype": "Currency", "options": doc.currency}) }} {% endif %}</td>
                    </tr>
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000;"><strong>SGST ({{ sgst_rate }}%)</strong></td>
                        <td style="text-align:right">{% if total_sgst > 0 %} {{ frappe.format(total_sgst, {"fieldtype": "Currency", "options": doc.currency}) }} {% endif %}</td>
                    </tr>
                {% else %}
                    <tr style="border-bottom:1px solid #000;">
                        <td style="border-right: 1px solid #000;"><strong>IGST ({{ igst_rate }}%)</strong></td>
                        <td style="text-align:right">{% if total_igst > 0 %} {{ frappe.format(total_igst, {"fieldtype": "Currency", "options": doc.currency}) }} {% endif %}</td>
                    </tr>
                {% endif %}

                <tr style="border-bottom:1px solid #000;">
                    {% set ns = namespace(disc_amt=0, disc_pct=0) %}
                    {% for i in doc.items %}
                        {% if i.discount_percentage and i.price_list_rate %}
                            {% set ns.disc_amt = ns.disc_amt + ((i.price_list_rate * i.discount_percentage / 100) * i.qty) %}
                            {% set ns.disc_pct = ns.disc_pct + i.discount_percentage %}
                        {% endif %}
                    {% endfor %}
                    <td style="border-right: 1px solid #000;"><strong> Discount {% if ns.disc_pct %} ({{ ns.disc_pct }}%) {% endif %} </strong></td>
                    <td style="text-align:right"> {{ frappe.format( ns.disc_amt, {"fieldtype":"Currency","options":doc.currency} ) }} </td>
                </tr>

                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>TCS</strong></td>
                    <td style="text-align:right"> {{ frappe.format(doc.tcs_amount or 0, {"fieldtype":"Currency","options":doc.currency}) }} </td>
                </tr>
                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>Round Off</strong></td>
                    <td style="text-align:right"> {{ frappe.format(doc.rounding_adjustment or 0, {"fieldtype":"Currency","options":doc.currency}) }} </td>
                </tr>
                <tr style="border-bottom:1px solid #000;">
                    <td style="border-right: 1px solid #000;"><strong>Total Amt</strong></td>
                    <td style="text-align:right"> {{ frappe.format(doc.rounded_total or 0, {"fieldtype":"Currency","options":doc.currency}) }} </td>
                </tr>
            </table>
        </td>
    </tr>
</table>

<div style="padding-left:3px; padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span style="font-weight:bold;">Total Amount (In words):</span> {{ doc.in_words }}
</div>

<div style="padding-left:3px; padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span>Our risk and responsibility cease on the delivery of the goods on transport.All the disputes under this bill will be settelled in the Mumbai Jurisdiction.</span>
</div>

<div style="padding-left:3px; padding-top:3px; font-size:10px; border-bottom: 1px solid #000;">
    <span>We hereby certify that our Registration Certificate under the Goods and Services Tax Act, 2017 is in force on the date on which the sale of the goods specified in this GST Invoice has been affected by us. This transaction of sale cover by "GST Invoice" has effected by us and it shall be accounted for in the turnover of sales while filling of return and the due tax, if any, payable on the sale has been paid or shall be paid.</span>
</div>

{% set qr_image_src = "" %}

{% if doc.irn %}
    {% set log_doc = frappe.get_doc("e-Invoice Log", doc.irn) %}
    {% if log_doc and log_doc.signed_qr_code %}
        {% set qr_image_src = "data:image/png;base64," + get_qr_code(log_doc.signed_qr_code) %}
    {% endif %}
{% endif %}

<table style="width: 100%; font-family: 'Helvetica Neue', Arial, sans-serif; border-bottom: 1px solid #111; border-collapse: collapse; table-layout: fixed;">
    <tr>
        <td style="width:35%; vertical-align: top !important; padding: 8px; border-top: 1px solid #000;">
            <div style="font-size:10px; line-height: 1.3; margin: 0;">
                {% set company_dets = frappe.get_doc("Company", doc.company) %}
                <b>GSTIN-{{ company_dets.gstin or " " }}</b><br>
                <b>PAN No-{{ company_dets.pan or " " }}</b><br>
                <b>BANK DETAILS-</b><br>
                {% set bank_dets = frappe.get_list("Bank Account", filters={"company": doc.company}, fields="name") %}
                {% if bank_dets %}
                    {% set bank_rec = frappe.get_doc("Bank Account", bank_dets[0].name) %}
                    BANK NAME:-{{ bank_rec.bank }}<br>
                    ACCOUNT NO:-{{ bank_rec.bank_account_no }}<br>
                    BANK BRANCH:-{{ bank_rec.branch_code }}<br>
                    RTGS/NEFT IFSC CODE:-{{ bank_rec.custom_ifsc_code or "BARB0MULUND" }}<br>
                {% endif %}
                RTGS/NOTE:-Please treat the 5th article as number "0" in RTGS code
            </div>
        </td>

        <td class="qr-cell-container" style="width:35%; border-left: 1px solid #000; border-right: 1px solid #000; border-top: 1px solid #000;">
            <div style="display: inline-block; width: 140px; height: 140px;">
                {% if qr_image_src %}
                    <img src="{{ qr_image_src }}" style="width: 100%; height: 100%; object-fit: contain; display: block;">
                {% else %}
                    <div style="font-size:8px; color:#888; border: 1px dashed #ccc; height: 130px; line-height: 130px; text-align: center;">
                        E-INVOICE QR NOT GENERATED
                    </div>
                {% endif %}
            </div>
        </td>

        <td style="width:30%; border-top: 1px solid #000; vertical-align: top !important; text-align: center; padding: 8px; height: 120px;">
            <div style="font-size:10px; margin: 0;"><strong>For, JAIN MACHINE TOOLS &amp; ELECTRICALS LLP</strong></div>
            <div style="margin-top: 35px;">
                {% if doc.company %}
                    {% set company_doc = frappe.get_doc('Company', doc.company) %}
                    {% if company_doc.custom_signature %}
                        <img src="{{ company_doc.custom_signature }}" style="width:65% !important;" /> 
                    {% endif %}
                {% endif %}
            </div>    
            <div style="margin-top: 50px; font-size:10px;"><strong>AUTHORIZED SIGNATORY</strong></div>
        </td>
    </tr>
</table>
{% endmacro %}
<!-- ================= MACROS END ================= -->

<!-- ================= FIXED LOGIC (Pagination) ================= -->
{% set ns = namespace(current_page=[], current_height=0, all_pages=[]) %}
{% set max_lines = 39 %}
{% set total_row_padding = 1 %}
{% for item in doc.items %}
    {% set newlines = ((item.description or "")|string).count('\n') %}
    {% set wraps = (((item.description or "")|length) / 50) | int %}
    {% set sn_lines = 1 if item.serial_no else 0 %}
    {% set lines = 1 + newlines + wraps + sn_lines %}
    {% set effective_lines = lines %}
    {% if loop.last %}{% set effective_lines = lines + total_row_padding %}{% endif %}
    {% if (ns.current_height + effective_lines) > max_lines %}
        {% set _ = ns.all_pages.append(ns.current_page) %}
        {% set ns.current_page = [item] %}
        {% set ns.current_height = lines %}
    {% else %}
        {% set _ = ns.current_page.append(item) %}
        {% set ns.current_height = ns.current_height + lines %}
    {% endif %}
{% endfor %}
{% if ns.current_page %}{% set _ = ns.all_pages.append(ns.current_page) %}{% endif %}

{% set last_page_items = ns.all_pages[-1] %}
{% set ns_last = namespace(h=0) %}
{% for i in last_page_items %}
    {% set nl = ((i.description or "")|string).count('\n') %}
    {% set wr = (((i.description or "")|length) / 50) | int %}
    {% set snl = 1 if i.serial_no else 0 %}
    {% set ns_last.h = ns_last.h + 1 + nl + wr + snl %}
{% endfor %}
{% set move_remarks = (ns_last.h + total_row_padding) > 14 %}

<!-- ================= RENDERING ================= -->
{% if doc.workflow_state == "Rejected" or doc.workflow_state != "Approved" %}
<div class="po-watermark"></div>
{% endif %}

{% set sr_no = namespace(val=0) %}
{% for batch in ns.all_pages %}
    {% set is_last_page = loop.last %}
    <div class="header-above-container">
        <div class="left"> {{ doc.name }} </div>
        <div class="right"> {{ frappe.utils.formatdate(doc.posting_date, "dd-MMM-yyyy") }} </div>
    </div>

    <div class="spring-container {% if not is_last_page or move_remarks %}page-break{% endif %}">
        <div class="content-wrapper">
            {{ render_header(doc, show_po_details=True) }}
            <table class="items-table" style="width:100%; border-bottom:1px solid #000;border-top:1px solid #000;">
                <thead>
                    <tr style="font-weight:bold; font-size:11px;">
                        <th width="5%" style="border-right:1px solid #000; text-align:center;"><strong>Sr. No.</strong></th>
                        <th width="35%" style="border-right:1px solid #000; text-align:center;"><strong>Description</strong></th>
                        <th width="10%" style="border-right:1px solid #000; text-align:center;"><strong>HSN Code</strong></th>
                        <th width="9%" style="border-right:1px solid #000; text-align:center;"><strong>Unit Rate</strong></th>
                        {% if paper.show_base_price %}<th width="9%;" style="border-right:1px solid #000; text-align:center;"><strong>Base Price</strong></th>{% endif %}
                        <th width="7%" style="border-right:1px solid #000; text-align:center;"><strong>Qty</strong></th>
                        <th width="9%" style="border-right:1px solid #000; text-align:center;"><strong>Discount %</strong></th>
                        <th width="9%" style="border-right:1px solid #000; text-align:center;"><strong>Handling</strong></th>
                        <th width="10%" style="text-align:center;"><strong>Net Amount</strong></th>
                    </tr>
                </thead>
                <tbody>
                    {% for row in batch %}
                    {% set sr_no.val = sr_no.val + 1 %}
                    <tr style="font-size:10px; border-bottom:1px solid #000; vertical-align: top;">
                        <td style="text-align:center; border-right:1px solid #000; padding-top:5px;">{{ sr_no.val }}</td>
                        <td style="border-right:1px solid #000; padding: 5px; text-align: left;">
                            <div style="white-space: pre-wrap;">{{ row.description }}</div>
                            {% if row.serial_no %}
                                <div style="font-size: 9px; color: #333; margin-top: 4px;">
                                    <strong>Serial No:</strong> {{ row.serial_no | replace("\n", ", ") }}
                                </div>
                            {% endif %}
                        </td>
                        <td style="text-align:center;border-right:1px solid #000; padding-top:5px;">{{ row.gst_hsn_code or "" }}</td>
                        <td style="text-align:right;border-right:1px solid #000; padding-top:5px;">
                            {{ frappe.format(row.rate, {"fieldtype": "Currency", "options": doc.currency}) }}</td>
                        {% if paper.show_base_price %}
                        <td style="text-align:center;border-right:1px solid #000; padding-top:5px;">
                            {% set ns_r = frappe.get_all("Non Standard Item Creation", filters={"new_item_code": row.description}, fields=["base_price"], limit=1) %}
                            {% if ns_r %} {{ "%.2f"|format(ns_r[0].base_price or 0) }} {% endif %}
                        </td>
                        {% endif %}
                        <td style="text-align:center;border-right:1px solid #000; padding-top:5px;">{{ row.qty|int or 0 }}</td>
                        <td style="text-align:right;border-right:1px solid #000; padding-top:5px;">{{ "%.2f"|format(row.discount_percentage or 0) }}</td>
                        <td style="text-align:right;border-right:1px solid #000; padding-top:5px;">{{ "%.2f"|format(row.handling_charges_value or 0) }}</td>
                        <td style="text-align:right; padding-top:5px;">
                            {{ frappe.format(row.amount, {"fieldtype": "Currency", "options": doc.currency}) }}</td>
                    </tr>
                    {% endfor %}
                    {% if is_last_page %}
                    <tr style="font-weight:bold; font-size:11px; background-color:#b6e1fb;">
                        <td colspan="2" style="border:1px solid #111; padding-left:5px;"> Total </td>
                        <td style="border:1px solid #111;"></td><td style="border:1px solid #111;"></td>
                        {% if paper.show_base_price %}<td style="border:1px solid #111;"></td>{% endif %}
                        <td style="border:1px solid #111; text-align:center;"> {{ doc.items | sum(attribute='qty')|int }} </td>
                        <td style="border:1px solid #111;"></td><td style="border:1px solid #111;"></td>
                        <td style="border:1px solid #111; text-align:right;">{{ frappe.format(doc.items | sum(attribute='net_amount'), {"fieldtype":"Currency", "options": doc.currency}) }}</td>
                    </tr>
                    {% endif %}
                </tbody>
            </table>
            {% if is_last_page and not move_remarks %}{{ render_remarks_and_totals(doc) }}{% endif %}
        </div>
        <div class="footer-wrapper"><img src="/files/JMT FOOTER.png" style="width: 100%; height: 60px;"></div>
    </div>

    {% if is_last_page and move_remarks %}
    <div class="spring-container">
        <div class="content-wrapper">
            {{ render_header(doc, show_po_details=False) }}
            <div style="margin-top: 0px;">{{ render_remarks_and_totals(doc) }}</div>
        </div>
        <div class="footer-wrapper"><img src="/files/JMT FOOTER.png" style="width: 100%; height: 60px;"></div>
    </div>
    {% endif %}
{% endfor %}

